import { useState } from "react";
import "./App.css";

function App() {
  const [searchName, setSearchName] = useState("");
  const [result, setResult] = useState([]);
  const [newFood, setNewFood] = useState({ name: "", calories: "", protein: "" });
  const [updateId, setUpdateId] = useState("");
  const [updateName, setUpdateName] = useState("");

  const searchFood = async () => {
    if (!searchName) return;
    const res = await fetch(`http://localhost:5000/food/${searchName}`);
    const data = await res.json();
    setResult(data);
  };

  const addFood = async () => {
    await fetch("http://localhost:5000/food", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(newFood),
    });
    alert("Food added");
    setNewFood({ name: "", calories: "", protein: "" });
  };

  const updateFood = async () => {
    if (!updateId) return;
    await fetch(`http://localhost:5000/food/${updateId}`, {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ name: updateName }),
    });
    alert("Food updated");
  };

  const deleteFood = async () => {
    if (!updateId) return;
    await fetch(`http://localhost:5000/food/${updateId}`, { method: "DELETE" });
    alert("Food deleted");
  };

  return (
    <div className="App" style={{ fontFamily: "Arial", margin: "40px" }}>
      <h2>Food Nutrition Database</h2>

      {/* Search */}
      <h3>Search Food</h3>
      <input
        placeholder="Enter food name"
        value={searchName}
        onChange={(e) => setSearchName(e.target.value)}
      />
      <button onClick={searchFood}>Search</button>

      <div style={{ marginTop: "20px" }}>
        {result.length > 0 && (
          <table style={{ borderCollapse: "collapse" }}>
            <thead>
              <tr>
                <th style={{ border: "1px solid #ccc", padding: "8px" }}>ID</th>
                <th style={{ border: "1px solid #ccc", padding: "8px" }}>Name</th>
                <th style={{ border: "1px solid #ccc", padding: "8px" }}>Calories</th>
              </tr>
            </thead>
            <tbody>
              {result.map((f) => (
                <tr key={f.id}>
                  <td style={{ border: "1px solid #ccc", padding: "8px" }}>{f.id}</td>
                  <td style={{ border: "1px solid #ccc", padding: "8px" }}>{f.name}</td>
                  <td style={{ border: "1px solid #ccc", padding: "8px" }}>{f.calories}</td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      <hr />

      {/* Add Food */}
      <h3>Add Food</h3>
      <input
        placeholder="Food name"
        value={newFood.name}
        onChange={(e) => setNewFood({ ...newFood, name: e.target.value })}
      />
      <input
        placeholder="Calories"
        value={newFood.calories}
        onChange={(e) => setNewFood({ ...newFood, calories: e.target.value })}
      />
      <input
        placeholder="Protein"
        value={newFood.protein}
        onChange={(e) => setNewFood({ ...newFood, protein: e.target.value })}
      />
      <button onClick={addFood}>Add</button>

      <hr />

      {/* Update / Delete */}
      <h3>Update / Delete</h3>
      <input
        placeholder="Food ID"
        value={updateId}
        onChange={(e) => setUpdateId(e.target.value)}
      />
      <input
        placeholder="New name"
        value={updateName}
        onChange={(e) => setUpdateName(e.target.value)}
      />
      <button onClick={updateFood}>Update</button>
      <button onClick={deleteFood} style={{ marginLeft: "10px" }}>Delete</button>
    </div>
  );
}

export default App;
